// src/app/dashboard/page.tsx
import { prisma } from "../../lib/prisma";
import ParetoChart from "../../components/paretoCharts";
import { Wallet } from "@prisma/client";

export default async function UserDashboard({ searchParams }: { searchParams: { period?: string } }) {
    const period = searchParams.period || "monthly";
    
    // --- LOGIKA AMBIL DATA (Sama seperti sebelumnya) ---
    const wallets = await prisma.wallet.findMany();
    const now = new Date();
    const startDate = period === "monthly" 
        ? new Date(now.getFullYear(), now.getMonth(), 1) 
        : new Date(now.getFullYear(), 0, 1);

    const expenses = await prisma.transaction.findMany({
        where: { type: "EXPENSE", createdAt: { gte: startDate } },
        include: { category: true },
    });

    // --- LOGIKA HITUNG PARETO (Group & Sort) ---
    const grouped = expenses.reduce((acc: any, curr) => {
        const catName = curr.category?.name || "Lainnya";
        acc[catName] = (acc[catName] || 0) + curr.amount;
        return acc;
    }, {});

    const totalExpense = Object.values(grouped).reduce((a: any, b: any) => a + b, 0) as number;
    let runningTotal = 0;
    const chartData = Object.entries(grouped)
        .map(([name, total]) => ({ name, total: total as number }))
        .sort((a, b) => b.total - a.total)
        .map((item) => {
        runningTotal += item.total;
        return { ...item, cumulative: totalExpense > 0 ? Math.round((runningTotal / totalExpense) * 100) : 0 };
        });

    return (
        <main className="p-8 bg-slate-50 min-h-screen">
        <div className="max-w-6xl mx-auto space-y-8">
            
            {/* 1. Header & Filter */}
            <div className="flex justify-between items-center">
            <h1 className="text-3xl font-bold text-slate-800">Dashboard Keuangan</h1>
            <div className="flex bg-white rounded-lg p-1 shadow-sm border border-slate-200">
                <a href="?period=monthly" className={`px-4 py-2 rounded-md text-sm ${period === 'monthly' ? 'bg-blue-600 text-white' : ''}`}>Bulanan</a>
                <a href="?period=yearly" className={`px-4 py-2 rounded-md text-sm ${period === 'yearly' ? 'bg-blue-600 text-white' : ''}`}>Tahunan</a>
            </div>
            </div>

            {/* 2. Kartu Saldo (Yang kemarin sudah jadi) */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {wallets.map((wallet: Wallet) => (
                <div key={wallet.id} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                <p className="text-xs font-bold text-slate-400 uppercase">{wallet.type}</p>
                <h2 className="text-lg font-bold">{wallet.name}</h2>
                <p className="text-2xl font-bold text-blue-600">Rp {wallet.balance.toLocaleString('id-ID')}</p>
                </div>
            ))}
            </div>

            {/* 3. PARETO CHART (Muncul di sini) */}
            <div className="mt-8">
            <ParetoChart data={chartData} />
            </div>

        </div>
        </main>
    );
}